INSERT INTO `jobs` VALUES (3,6,'Articleship Trainee','Pune','Articleship','Taxation','On-site','Fresher',2,'[\"Taxation\",\"Audit\",\"Tax\"]',NULL,'CA Intermediate (Both Groups / Single Group) cleared or appearing candidates with strong analytical skills, basic accounting knowledge, and willingness to learn professional compliance and audit work.','2026-05-30','15000','We are looking for motivated and dedicated CA Articleship Trainees to join our growing Chartered Accountancy firm. The selected candidates will gain practical exposure across Audit, Taxation, GST, ROC Compliance, Accounting, and Financial Advisory assignments while working closely with experienced Chartered Accountants.\n\nThis role is ideal for CA Intermediate students who are eager to build strong professional and technical skills through hands-on client work and real-time business exposure.\n\nRoles and Responsibilities :\n\n• Assist in statutory audits, tax audits, and internal audits\n• Prepare and review financial statements and audit documentation\n• Support GST return filing, income tax return preparation, and compliance work\n• Handle ROC filings, registrations, and regulatory documentation\n• Work on accounting entries, bank reconciliations, and MIS reporting\n• Participate in client meetings and data collection activities\n• Assist senior team members in advisory and consultancy assignments\n• Maintain proper documentation and working papers\n• Coordinate with clients for pending information and compliance follow-ups\n\nBenefits\n• Structured practical training under experienced Chartered Accountants\n• Exposure to multiple industries and real client assignments\n• Department-wise learning opportunities in Audit, Taxation, GST, and Compliance\n• Mentorship and professional guidance throughout articleship period\n• Friendly and growth-oriented work culture\n• Performance-based stipend increments\n• Opportunity to work on advanced accounting and taxation software\n• Exam leave support as per 